-bool NoopCoroElider::tryEraseCallInvoke(Instruction *I) {
-  if (auto *Call = dyn_cast<CallInst>(I)) {
-    Call->eraseFromParent();
-    return true;
-  }
-
-  if (auto *II = dyn_cast<InvokeInst>(I)) {
-    Builder.SetInsertPoint(II);
-    Builder.CreateBr(II->getNormalDest());
-    II->eraseFromParent();
-    return true;
-  }
-  return false;
-}
